INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('0adc27ee6c56c701', 'NE', '["federal","state","county"]', 'ballot_access', 'What is the primary election system in Nebraska?', '["Are Nebraska primaries open or closed?","Can unaffiliated voters participate in the Nebraska primary?","Nebraska primary voting rules"]', 'Nebraska''s primary system varies significantly by office. For the state legislature, the primary is a nonpartisan top-two blanket primary where any registered voter can participate. For congressional and statewide offices, primaries are partisan. Unaffiliated voters may request a partisan ballot for congressional races, but for statewide executive offices, each political party independently decides whether to allow unaffiliated voters to participate in their primary.', 'https://sos.nebraska.gov/elections/voter-information', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All voters and candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('3cdb8b0f13f6bdef', 'NE', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Nebraska for 2026?', '["Nebraska primary date 2026","When is Election Day 2026 in Nebraska?","May primary Nebraska"]', 'The Nebraska primary election will be held on Tuesday, May 12, 2026. The general election will be held on Tuesday, November 3, 2026. Polls are open from 8:00 a.m. to 8:00 p.m. in the Central Time Zone, and 7:00 a.m. to 7:00 p.m. in the Mountain Time Zone.', 'https://civicnebraska.org/election-2026/cal/', 'Civic Nebraska - Election Calendar', '2026-05-17', 'per_cycle', 'secondary_source', 'All candidates and voters', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('c44994df65051ec2', 'NE', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline in Nebraska for 2026?', '["When do candidates file for office in Nebraska?","Nebraska filing deadline 2026","Incumbent filing deadline NE"]', 'Nebraska utilizes split filing deadlines for the primary election. Incumbent officeholders must file their candidate paperwork by February 17, 2026. Non-incumbent challengers have until March 2, 2026, to file their candidacy.', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State - Candidate Info', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('5f5e8ee096ae5fb2', 'NE', '["state"]', 'ballot_access', 'What is unique about the structure of the Nebraska State Legislature?', '["Nebraska unicameral legislature","Is the Nebraska legislature nonpartisan?","How many chambers in the NE legislature?"]', 'Nebraska holds the major constitutional distinctive of being the ONLY state in the nation with a unicameral (single-chamber) legislature. The body has 49 members (State Senators). Furthermore, the legislature is officially nonpartisan; candidates are elected via a top-two primary and their political party affiliations are not listed on the ballot.', 'https://nebraskalegislature.gov/about/history.php', 'Nebraska Legislature History', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('d0dfc8d6f86bbc10', 'NE', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in Nebraska?', '["Do write-in votes count in NE?","How to register as a write-in candidate in Nebraska","Write-in filing deadline Nebraska"]', 'Yes. Write-in candidates are permitted, but they must officially file a notarized affidavit of intent along with the required filing fee. To have their votes tabulated in the general election, the candidate must file this paperwork with the appropriate election official no later than the second Friday before the election.', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('a0008df68fd1fc1b', 'NE', '["federal","state"]', 'ballot_access', 'What is the petition signature threshold for independent candidates in Nebraska?', '["Independent candidate ballot access Nebraska","Running without a party in NE 2026","How many signatures for independent US Senate NE"]', 'Independent (unaffiliated) candidates for partisan offices bypass the primary and petition directly onto the general election ballot. For statewide offices (like U.S. Senate or Governor), they must submit at least 4,000 valid signatures from registered voters. For U.S. House, they need 2,000 signatures. The deadline to file is September 1.', 'https://ballotpedia.org/United_States_House_of_Representatives_elections_in_Nebraska,_2026', 'Ballotpedia / Nebraska Revised Statutes', '2026-05-17', 'static', 'secondary_source', 'Independent candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('25990973062e3b7f', 'NE', '["federal","state","county"]', 'ballot_access', 'Does Nebraska have a sore loser law?', '["Can I run as an independent if I lose the NE primary?","Nebraska sore loser statute","General election ballot access after primary defeat NE"]', 'Yes. Nebraska enforces a sore loser law under Neb. Rev. Stat. § 32-615. A candidate whose name appeared on the primary election ballot and was defeated for the nomination cannot subsequently have their name placed on the general election ballot by petition or as a write-in candidate for that same office.', 'https://nebraskalegislature.gov/laws/statutes.php?statute=32-615', 'Nebraska Revised Statutes § 32-615', '2026-05-17', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('8df67442dfaf3b2b', 'NE', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Nebraska?', '["Nebraska joint ticket rules","How are Lt Gov candidates selected in NE?","Does the Governor pick a running mate in Nebraska?"]', 'In Nebraska, the Governor and Lieutenant Governor run as a joint ticket in the general election. However, they do not run together in the primary. The gubernatorial candidate runs independently in the primary and, upon securing the nomination, designates their Lieutenant Governor running mate for the November ballot.', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('7b1f92f83285564b', 'NE', '["federal"]', 'election_dates', 'How does Nebraska allocate its Electoral College votes?', '["Nebraska split electoral votes","Congressional district method NE","Does the winner take all electoral votes in Nebraska?"]', 'Nebraska is one of only two states (along with Maine) that uses the congressional district method to allocate its Electoral College votes, rather than winner-take-all. The state awards 2 at-large electoral votes to the statewide popular vote winner, and 1 electoral vote to the popular vote winner within each of its 3 congressional districts. NE-2 (Omaha) has historically split from the statewide vote (e.g., 2008, 2020).', 'https://sos.nebraska.gov/elections/electoral-college', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('6df0dbe8f7c52259', 'NE', '["state"]', 'election_dates', 'Is Governor Jim Pillen running for re-election in 2026?', '["Nebraska Governor election 2026","Who is defending the NE Governor seat?","Is Jim Pillen on the 2026 ballot?"]', 'Yes. Governor Jim Pillen (R) was first elected in 2022 and is eligible to defend his seat for a second four-year term in the 2026 midterm election.', 'https://ballotpedia.org/Governor_of_Nebraska', 'Ballotpedia - Governor of Nebraska', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('d9b6d514ded839d6', 'NE', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Nebraska in 2026?', '["Is Pete Ricketts up for re-election in 2026?","When is Deb Fischer''s next election?","Nebraska US Senate cycle 2026"]', 'The Class 2 U.S. Senate seat currently held by Pete Ricketts (R) is up for election in 2026. Ricketts was appointed in 2023 and won a special election in 2024 to complete the term; he is now seeking his first full six-year term. Senator Deb Fischer (Class 1) was re-elected in 2024 and is next up in 2030.', 'https://www.senate.gov/senators/Class_II.htm', 'U.S. Senate - Class II Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('401f3d87d6f9569d', 'NE', '["federal"]', 'election_dates', 'How many U.S. House districts are in Nebraska for the 2026 election?', '["Nebraska congressional apportionment","Are all NE congressional seats up in 2026?","Number of US Representatives from Nebraska"]', 'Nebraska is apportioned 3 U.S. House districts. All three seats are on the 2026 ballot for two-year terms, with NE-2 traditionally being a highly competitive battleground district.', 'https://ballotpedia.org/United_States_House_of_Representatives_elections_in_Nebraska,_2026', 'Ballotpedia', '2026-05-17', 'static', 'secondary_source', 'Federal candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('174a3a0837d20590', 'NE', '["state"]', 'election_dates', 'Which Nebraska State Legislature seats are up for election in 2026?', '["Are all Nebraska Senate seats up in 2026?","Nebraska Unicameral election cycle 2026","Which legislative districts are on the ballot in NE?"]', 'The Nebraska Unicameral Legislature is composed of 49 State Senators who serve four-year staggered terms. In the 2026 election cycle, the 24 even-numbered legislative districts will be on the ballot.', 'https://nebraskalegislature.gov/about/history.php', 'Nebraska Legislature', '2026-05-17', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('2cf876c5e3badb29', 'NE', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Nebraska in 2026?', '["Is the Attorney General up in 2026?","NE statewide election list 2026","When is the Secretary of State election in NE?"]', 'Nebraska elects its major statewide executive officers concurrently on a four-year midterm cycle. In 2026, the offices of Governor, Lieutenant Governor, Secretary of State, Attorney General, State Treasurer, and Auditor of Public Accounts are all on the ballot.', 'https://sos.nebraska.gov/', 'Nebraska Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('e7dd49c611c0dc11', 'NE', '["state"]', 'election_dates', 'What is the schedule for the Nebraska State Legislature sessions?', '["When does the NE legislature meet?","Nebraska 90 day legislative session","Is the Nebraska legislature full time?"]', 'The Nebraska Unicameral is a part-time legislature that meets annually. Sessions begin on the first Wednesday after the first Monday in January. In odd-numbered years, the session lasts for 90 legislative days. In even-numbered election years (like 2026), it is a ''short session'' lasting 60 legislative days.', 'https://nebraskalegislature.gov/', 'Nebraska Legislature', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('c27a397267f36224', 'NE', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Nebraska?', '["Age and residency for Nebraska Governor","Nebraska Constitution Governor qualifications","Who is eligible to be Governor of NE?"]', 'Under Article IV, Section 2 of the Nebraska Constitution, a candidate for Governor must be at least 30 years old, a citizen of the United States, and must have been a resident of Nebraska for at least five years next preceding the election.', 'https://nebraskalegislature.gov/laws/articles.php?article=IV-2', 'Nebraska Constitution Article IV', '2026-05-17', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('2ff35ea1990222e3', 'NE', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Nebraska State Legislature?', '["Qualifications for NE State Senator","Age requirement Nebraska Unicameral","Do I have to live in my district to run in NE?"]', 'A candidate for the Nebraska Legislature must be a registered voter, at least 21 years of age, and a resident of the legislative district they seek to represent for exactly one year prior to the general election.', 'https://nebraskalegislature.gov/laws/articles.php?article=III-8', 'Nebraska Constitution Article III', '2026-05-17', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('572d57651add3fe8', 'NE', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Nebraska?', '["US Senate residency requirements Nebraska","Age to run for Congress in Nebraska","Federal constitutional requirements for NE candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be at least 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('211ee69dcf52c0e6', 'NE', '["state"]', 'candidate_eligibility', 'What are the term limits for the Nebraska Governor?', '["How many terms can a Nebraska Governor serve?","Jim Pillen term limits NE","Nebraska executive term limit law"]', 'Under the Nebraska Constitution, the Governor is limited to serving two consecutive four-year terms. After serving two terms, the individual is ineligible to run for the office again until one full term has intervened.', 'https://nebraskalegislature.gov/laws/articles.php?article=IV-1', 'Nebraska Constitution Article IV', '2026-05-17', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('e7951ace43d16495', 'NE', '["state"]', 'candidate_eligibility', 'Does Nebraska have legislative term limits?', '["How many terms can a Nebraska state senator serve?","Are there term limits for the Nebraska Unicameral?","Nebraska legislature term limit status"]', 'Yes. Members of the Nebraska Legislature are subject to strict term limits. State Senators are limited to serving a maximum of two consecutive four-year terms (8 consecutive years). After sitting out for one term, they may run again.', 'https://nebraskalegislature.gov/about/history.php', 'Nebraska Legislature', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('8cf79cf8a3f3812d', 'NE', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Attorney General in Nebraska?', '["Qualifications to run for Attorney General in NE","Do I need to be a member of the bar to be NE AG?","Legal requirements for Nebraska Attorney General"]', 'To run for Attorney General in Nebraska, a candidate must be a citizen of the United States, a resident of the state, and practically, must be an attorney admitted to practice law in the Supreme Court of Nebraska (statutory requirement).', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('72e807b9f8fe7ae1', 'NE', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in Nebraska?', '["Nebraska county commissioner qualifications","Can I run for county board in NE?","County residency for NE officials"]', 'To run for a county office (such as County Commissioner, Clerk, or Sheriff) in Nebraska, a candidate must be a registered voter and a resident of the county (and the specific district, if applicable) they seek to serve.', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('15d35432ecb3e4ce', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Nebraska?', '["Nebraska voter ID requirements","Do I need my driver''s license to vote in NE?","Acceptable ID for Nebraska voting"]', 'Yes. In an accuracy correction to older baselines: following a 2022 voter-approved constitutional amendment, the legislature enacted LB514 in 2023 implementing strict photo ID requirements. Acceptable IDs include a Nebraska driver''s license, state ID, U.S. Passport, military ID, tribal ID, or a Nebraska college/university ID. If a voter lacks ID, they may vote provisionally or submit a reasonable impediment certification.', 'https://sos.nebraska.gov/voter-id', 'Nebraska Secretary of State - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('83462bef4d1e1cc5', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Nebraska a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in Nebraska?","Nebraska vote-by-mail system","Do I need an excuse to vote absentee in NE?"]', 'Nebraska is not a universal mail ballot state (ballots are not mailed to all voters automatically). However, the state does allow for NO-EXCUSE absentee voting (referred to as early voting by mail). Any registered voter may request an early voting ballot without providing a reason.', 'https://sos.nebraska.gov/elections/early-voting', 'Nebraska Secretary of State - Early Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('707bb10dc41c486d', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Nebraska offer early in-person voting?', '["Can I vote early in person in NE?","Nebraska early voting dates 2026","When does early voting start in Nebraska?"]', 'Yes. Nebraska offers in-person early voting at county election offices. This early voting period begins 30 days prior to the election and concludes the day before Election Day.', 'https://sos.nebraska.gov/elections/early-voting', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('a94172f885ccbe8e', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Nebraska offer same-day registration?', '["Last day to register to vote in NE","Nebraska same day voter registration","Voter registration deadline 2026 Nebraska"]', 'Nebraska has split deadlines. Online or mailed registrations must be completed or postmarked by the 3rd Friday before the election (October 16, 2026, for the general). In-person registration at the county election office is permitted until 6:00 p.m. on the 2nd Friday before the election (October 23, 2026). Nebraska DOES NOT offer same-day registration at the polls.', 'https://civicnebraska.org/election-2026/cal/', 'Civic Nebraska / Secretary of State', '2026-05-17', 'static', 'secondary_source', 'Voters', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('1d22a32f1285fc44', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Nebraska?', '["How close can I campaign to a polling place in NE?","Nebraska 200 feet electioneering rule","NE buffer zone around voting centers"]', 'Under Nebraska law (Neb. Rev. Stat. § 32-1524), electioneering is strictly prohibited within the polling place, within any building housing a polling place, or within 200 feet of the entrance to the building where voting is occurring.', 'https://nebraskalegislature.gov/laws/statutes.php?statute=32-1524', 'Nebraska Revised Statutes § 32-1524', '2026-05-17', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('be6592f10beaf9c2', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Nebraska?', '["Can felons vote in Nebraska state?","Felony voting rights restoration NE","Voting on parole in Nebraska"]', 'In a major 2024 reform (LB20), Nebraska removed its previous two-year waiting period. Individuals convicted of a felony now have their voting rights automatically restored immediately upon the completion of their full sentence, which includes all prison time, probation, and parole.', 'https://nebraskalegislature.gov/bills/view_bill.php?DocumentID=54129', 'Nebraska Legislature (LB20)', '2026-05-17', 'static', 'statute_citation', 'Voters', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('7ffbabfe77882619', 'NE', '["county"]', 'voter_interaction', 'How many counties are in Nebraska, and who administers elections locally?', '["Nebraska county election administration","How many county clerks in NE?","Local election control Nebraska"]', 'Nebraska is divided into 93 counties. Election administration is handled at the local level by County Clerks, or in larger jurisdictions, by specifically appointed Election Commissioners. Campaigns must coordinate with these 93 offices for ballot logistics and early voting data.', 'https://sos.nebraska.gov/elections/election-officials-contact-information', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('4546454bed86e552', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Nebraska voter file?', '["Nebraska voter database access cost","How to get the voter list in NE","What data is included in the Nebraska voter file?"]', 'Registered political committees and candidates can purchase the statewide voter registration list from the Secretary of State''s office. The file contains voter names, addresses, party affiliations, and election history. The data is legally restricted to election-related and political purposes.', 'https://sos.nebraska.gov/elections/voter-registration-data', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('32167bf1cdcbf8ce', 'NE', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Nebraska?', '["Where do I file campaign finance reports in NE?","What is the Nebraska Accountability and Disclosure Commission?","Does the NE Secretary of State handle campaign finance?"]', 'In Nebraska, campaign finance and disclosure laws are administered and enforced exclusively by the Nebraska Accountability and Disclosure Commission (NADC), an independent ethics agency, rather than the Secretary of State.', 'https://nadc.nebraska.gov/', 'Nebraska Accountability and Disclosure Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('699c3f4afa2cd836', 'NE', '["state","county"]', 'finance_ethics', 'What are the individual campaign contribution limits in Nebraska for the 2026 cycle?', '["Are there contribution limits in Nebraska?","NE individual donation caps 2026 election","Maximum donation to state legislature Nebraska"]', 'Nebraska has a major campaign finance distinctive: there are NO contribution limits for individuals donating to state, legislative, or local candidates. Individuals may contribute an UNLIMITED amount of money to political campaigns.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC - Treasurer''s Guide', '2026-05-17', 'static', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('c7fe2635827db69d', 'NE', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Nebraska campaigns?', '["Corporate contribution ban Nebraska state","Can a business donate to my campaign in NE?","Corporate campaign finance rules Nebraska"]', 'Yes. Because Nebraska imposes no overarching contribution limits, direct contributions from the general treasury of a corporation or labor union to a candidate''s campaign committee are PERMITTED and are unlimited.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC', '2026-05-17', 'static', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('86d7df88b87a01fe', 'NE', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Nebraska candidates?', '["NE NADC filing dates 2026","When are campaign finance reports due in NE?","Nebraska pre-primary and pre-general report deadlines"]', 'Candidates must file periodic Campaign Statements (Form B-1) with the NADC. During an election year, reports are due 30 days before the election, 10 days before the election, and 40 days after the election (for both the primary and general). In non-election years, an annual report is due.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC - Treasurer''s Guide', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('84b8f831e341eae3', 'NE', '["state","county","municipal"]', 'finance_ethics', 'What are Nebraska''s rapid disclosure requirements for late contributions?', '["Nebraska 48-hour large contribution report","Late contribution reporting Nebraska NADC","When do I file a rapid report in NE?"]', 'If a candidate committee receives a ''late contribution'' of $1,000 or more during the 14 days immediately preceding an election, they must file a Report of Late Contribution (Form B-5) with the NADC within 48 hours of receiving the funds.', 'https://nadc.nebraska.gov/sites/default/files/doc/B-5%202026.pdf', 'Nebraska NADC - Form B-5', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('bb1864ea423c526d', 'NE', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Nebraska?', '["NE NADC late fee","Penalty for missing a Nebraska campaign finance deadline","NADC fine for late filing NE"]', 'The NADC imposes strict, escalating penalties. For failing to file a Report of Late Contribution, the penalty is $100 for each of the first 10 days the report is late. Beginning on the 11th day, an additional daily late fee of 1% of the undisclosed amount is assessed (capped at 10%). Standard periodic reports incur $25 per day up to $750.', 'https://nadc.nebraska.gov/enforcement', 'Nebraska NADC - Enforcement', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('d2aaf383bdf6546a', 'NE', '["state"]', 'finance_ethics', 'Does Nebraska provide public financing for state campaigns?', '["Public matching funds for Nebraska Governor","State funded campaigns Nebraska status","Government campaign grants NE"]', 'No. Following the repeal of the state''s Campaign Finance Limitation Act (CFLA), Nebraska does not currently provide any system of public financing or matching funds for state-level political campaigns.', 'https://nadc.nebraska.gov/', 'Nebraska Accountability and Disclosure Commission', '2026-05-17', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('2917275a0ed0cb59', 'NE', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Nebraska?', '["NE personal use prohibition campaign finance","Can I use campaign money for personal items in NE?","Prohibited expenditures Nebraska NADC"]', 'Yes. Under the Nebraska Political Accountability and Disclosure Act, campaign funds are strictly prohibited from being converted to personal use. Expenditures must bear a direct relationship to the candidate''s campaign or the necessary expenses of holding public office.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC - Treasurer''s Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('37dd3e8ace7a33e1', 'NE', '["state"]', 'ballot_access', 'What is the signature threshold for a citizen statutory initiative in Nebraska?', '["How many signatures to pass a law in Nebraska?","Nebraska statutory initiative threshold","Qualifying a ballot measure in NE"]', 'To qualify a statutory initiative for the ballot in Nebraska, proponents must collect valid signatures from registered voters equal to at least 7% of the total number of registered voters in the state on the deadline date for submitting signatures.', 'https://sos.nebraska.gov/elections/initiative-and-referendum', 'Nebraska Secretary of State - Initiative and Referendum', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('23505c6778575213', 'NE', '["state"]', 'ballot_access', 'What is the signature threshold for a constitutional amendment initiative in Nebraska?', '["How to amend the Nebraska Constitution by citizen petition","Nebraska constitutional amendment signature requirement","Citizen initiative constitutional amendment NE"]', 'To place a citizen-initiated constitutional amendment on the ballot, proponents must gather valid signatures equal to at least 10% of the total number of registered voters in Nebraska as of the signature submission deadline.', 'https://sos.nebraska.gov/elections/initiative-and-referendum', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('83b55b05e61fad1b', 'NE', '["state"]', 'ballot_access', 'What is the signature threshold for a veto referendum in Nebraska?', '["How to repeal a law in Nebraska","Nebraska veto referendum signature requirements","Referendum process NE"]', 'Citizens can use a veto referendum to repeal a legislative act. To simply place the referendum on the ballot for a vote, signatures equal to 5% of registered voters are required. (If proponents gather signatures equal to 10% of registered voters, the law is entirely suspended from taking effect until voters decide the issue at the election).', 'https://sos.nebraska.gov/elections/initiative-and-referendum', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('90ae4d64f8aeaeae', 'NE', '["state"]', 'ballot_access', 'How does the Nebraska Unicameral Legislature refer a constitutional amendment to the voters?', '["Legislative referral process Nebraska","Can the Nebraska legislature put an amendment on the ballot?","Supermajority to refer amendment NE"]', 'The Nebraska Legislature (the Unicameral) can refer a constitutional amendment to the general election ballot by securing a three-fifths (60%) supermajority vote of all elected members. Since there are 49 State Senators, an amendment requires 30 affirmative votes to be referred to the voters.', 'https://nebraskalegislature.gov/laws/articles.php?article=XVI-1', 'Nebraska Constitution Article XVI', '2026-05-17', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('80881764806c4c38', 'NE', '["federal","state"]', 'redistricting', 'Who draws Nebraska''s congressional and state legislative maps?', '["Does the NE legislature draw district maps?","Who has the authority to draw district lines in Nebraska?","Nebraska redistricting commission"]', 'In Nebraska, the state legislature (the Unicameral) holds the exclusive authority to draw and enact both congressional and state legislative district boundaries. The maps are passed as regular legislation and are subject to the Governor''s signature or veto.', 'https://ballotpedia.org/Redistricting_in_Nebraska', 'Ballotpedia - Redistricting in Nebraska', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('3eaac537ed9daadc', 'NE', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Nebraska?', '["Standards for drawing Nebraska district lines","Nebraska gerrymandering rules","Map requirements NE"]', 'Under the Nebraska Constitution and legislative guidelines, districts must be compact, contiguous, and as nearly equal in population as practicable. The guidelines also stipulate that county boundaries should be followed whenever practicable, and districts should not be drawn to intentionally dilute the voting strength of minority populations.', 'https://nebraskalegislature.gov/laws/articles.php?article=III-5', 'Nebraska Constitution Article III', '2026-05-17', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('741956047c297928', 'NE', '["federal"]', 'redistricting', 'Are the 2021 congressional maps operative for the 2026 cycle in Nebraska?', '["Status of Nebraska congressional redistricting","Omaha NE-2 gerrymandering controversy","Nebraska congressional boundaries 2026"]', 'Yes. The congressional maps enacted by the Unicameral in 2021 remain fully operative for the 2026 elections. Because Nebraska allocates Electoral College votes by congressional district, the boundaries of NE-2 (centered on Omaha) were highly contested, with Republicans altering its borders slightly to make it more competitive, but it remains the state''s prime battleground.', 'https://nebraskalegislature.gov/', 'Nebraska Legislature', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('fb1e6b4f9d0ac805', 'NE', '["state"]', 'recall_rules', 'Does Nebraska have a recall mechanism for state officials?', '["Can the Governor of Nebraska be recalled?","How to recall a state senator in NE","Statewide recall election rules Nebraska"]', 'No. The State of Nebraska does not have any legal or constitutional mechanism permitting the recall of state-level elected officials, including the Governor, statewide executives, or members of the Unicameral Legislature.', 'https://ballotpedia.org/Laws_governing_recall_in_Nebraska', 'Laws governing recall in Nebraska', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('5a5566e665f6c805', 'NE', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Nebraska?', '["Nebraska county commissioner recall rules","Signature requirement local recall Nebraska","Recalling a mayor in NE"]', 'Yes. Nebraska law (Neb. Rev. Stat. § 32-1302) provides a universal right to recall local elected officials (city, county, school district). A recall petition must be signed by registered voters equal to at least 35% of the total vote cast for that office in the last general election (with special rules for at-large seats).', 'https://nebraskalegislature.gov/laws/statutes.php?statute=32-1302', 'Nebraska Revised Statutes § 32-1302', '2026-05-17', 'static', 'statute_citation', 'Local candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('028df80ee9f04084', 'NE', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in Nebraska?', '["Requirements to run for NE Secretary of State","Who can run for Secretary of State in NE?","Residency rules for Nebraska SOS"]', 'To run for Secretary of State in Nebraska, a candidate must be a citizen of the United States, at least 18 years old, and a qualified elector (registered voter) and resident of the state. Unlike the Governor, there is no constitutional 30-year age requirement for the SOS.', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('79085e0453a8af0c', 'NE', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Treasurer in Nebraska?', '["Eligibility for Nebraska State Treasurer","Who can run for Treasurer in NE?","Nebraska Treasurer term limits"]', 'The qualifications for State Treasurer in Nebraska mirror those for the Secretary of State. A candidate must be a U.S. citizen, at least 18 years old, and a qualified elector and resident of Nebraska. The Treasurer is subject to a limit of two consecutive four-year terms.', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('efb88b90d7dac9e5', 'NE', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Nebraska?', '["Nebraska Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in NE?","Qualifications for Lieutenant Governor of Nebraska"]', 'Under Article IV, Section 2 of the Nebraska Constitution, the qualifications for Lieutenant Governor are identical to those for the Governor. A candidate must be at least 30 years old, a U.S. citizen, and a resident of Nebraska for at least five years preceding the election.', 'https://nebraskalegislature.gov/laws/articles.php?article=IV-2', 'Nebraska Constitution Article IV', '2026-05-17', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('5a91f5eca7161458', 'NE', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Nebraska?', '["Run for school board Nebraska requirements","Who can be a school board member in NE?","School board residency rules Nebraska"]', 'To run for a local Board of Education in Nebraska, a candidate must be a registered voter and a resident of the specific school district they seek to represent at the time of filing for office.', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State - Candidate Info', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('fa6c2f03c89a471d', 'NE', '["judicial"]', 'candidate_eligibility', 'How are Nebraska Supreme Court justices selected and what are the qualifications?', '["Nebraska Supreme Court Justice eligibility","Are Nebraska judges elected or appointed?","Merit selection of judges Nebraska"]', 'Nebraska uses the ''Missouri Plan'' (merit selection). Supreme Court justices are appointed by the Governor from a list submitted by a judicial nominating commission. To be eligible, a justice must be at least 30 years old, a U.S. citizen, a resident of Nebraska for at least three years, and admitted to practice law in the state.', 'https://supremecourt.nebraska.gov/administration/judicial-nominating-commission', 'Nebraska Judicial Branch', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('7a6dc269ba1eb4d6', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee mail-in ballots in Nebraska?', '["How to fix a rejected signature in NE","Nebraska ballot cure process deadline","Missing ID on NE early voting ballot"]', 'Following the passage of LB514 (2023) enforcing voter ID, Nebraska instituted a cure process. If an early voting (absentee) ballot return envelope is missing a signature or the required ID information, the county election official must notify the voter. The voter then has until the end of the business day on the Tuesday following the election to cure the defect.', 'https://sos.nebraska.gov/voter-id', 'Nebraska Secretary of State - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('87bd5bdf645b5203', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Nebraska?', '["When are military ballots due in Nebraska?","UOCAVA return deadline NE","Overseas voting rules Nebraska state"]', 'Under UOCAVA, early voting ballots are transmitted to military and overseas voters at least 45 days before an election. Voted ballots must be received by the county election office by the close of polls (8:00 p.m. Central / 7:00 p.m. Mountain) on Election Day to be counted.', 'https://sos.nebraska.gov/elections/military-and-overseas-voters', 'Nebraska Secretary of State - UOCAVA', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('5834d956f9f370c6', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Nebraska and how are they cured?', '["What is a provisional ballot in NE?","Voting without ID Nebraska","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued if a voter''s name is not on the precinct roster, if they moved without updating their registration, or if they fail to present acceptable photo ID. If cast due to lack of ID, the voter must present their valid photo ID to their county election office by the end of the business day on the Tuesday following the election for the ballot to count.', 'https://sos.nebraska.gov/voter-id', 'Nebraska Secretary of State - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('b7d0dc56aa87d326', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Nebraska have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Nebraska DMV?","NE motor voter automatic registration","Do I have to register to vote if I get a NE driver''s license?"]', 'No. Nebraska does NOT have Automatic Voter Registration (AVR). While the state complies with federal Motor Voter laws by offering individuals the opportunity to register to vote when applying for a driver''s license, the process requires the voter to actively opt-in and complete the registration fields.', 'https://sos.nebraska.gov/elections/voter-information', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('3272c5d84de622ff', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Nebraska offer Online Voter Registration?', '["Can I register to vote online in NE?","Nebraska electronic voter registration","NE online registration portal"]', 'Yes. Eligible Nebraska residents who possess a valid Nebraska driver''s license or state identification card can securely register to vote or update their registration using the Secretary of State''s online voter registration system.', 'https://www.nebraska.gov/apps-sos-voter-registration/', 'Nebraska Secretary of State - OVR', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('41e317337fe24ba2', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Nebraska maintain its voter registration lists?', '["NE voter list maintenance rules","How are inactive voters handled in Nebraska?","Nebraska voter roll cleaning process"]', 'Nebraska maintains its voter rolls using National Change of Address (NCOA) data and death records provided by the Department of Health and Human Services. Voters who are mailed a confirmation notice, fail to respond, and subsequently do not vote in two consecutive federal general elections are removed from the active rolls.', 'https://sos.nebraska.gov/elections/voter-information', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('88a1ce230201c296', 'NE', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee mail-in ballot in Nebraska?', '["When is the last day to mail my ballot in NE?","Nebraska early voting ballot return deadline","What time are ballots due in Nebraska?"]', 'All voted early voting (absentee) ballots must be physically received by the county election office by the close of polls (8:00 p.m. Central Time / 7:00 p.m. Mountain Time) on Election Day. Nebraska does NOT accept late-arriving ballots based on postmark dates.', 'https://sos.nebraska.gov/elections/early-voting', 'Nebraska Secretary of State - Early Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('d7d9473954839338', 'NE', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Nebraska?', '["Does Nebraska use ranked choice voting?","RCV status in Nebraska 2026","Instant runoff voting NE"]', 'No. Ranked Choice Voting (RCV) is not used in Nebraska for any statewide, federal, or state legislative elections. The state relies strictly on a traditional plurality voting system for partisan offices and a top-two advance system for its nonpartisan legislature.', 'https://sos.nebraska.gov/', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('889f77b19fe7d38a', 'NE', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in Nebraska elections?', '["How are tied elections decided in Nebraska?","Tie-breaker rules Nebraska elections","What happens if a race is tied in NE?"]', 'Under Nebraska Revised Statutes § 32-1122, if two or more candidates receive an equal and highest number of votes for an office, the tie is broken by the casting of lots (e.g., drawing names or a coin toss). The tie-breaker is conducted by the appropriate canvassing board or the Secretary of State.', 'https://nebraskalegislature.gov/laws/statutes.php?statute=32-1122', 'Nebraska Revised Statutes § 32-1122', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('e9b4ba1fd6646187', 'NE', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Nebraska campaign materials?', '["Nebraska ''Paid for by'' rules","Campaign ad disclaimer requirements NE","Political taglines Nebraska NADC"]', 'Nebraska campaign finance law requires that printed and broadcast political materials must clearly state ''Paid for by'' followed by the name and street address of the person, candidate, or committee that paid for the communication.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC - Treasurer''s Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('252c4b07f0b3fb53', 'NE', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Nebraska?', '["NE campaign coordination rules","When is a PAC expenditure not independent in Nebraska?","Prohibition on candidate-PAC coordination NE"]', 'An expenditure is no longer considered ''independent'' if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their committee. In Nebraska, a coordinated expenditure is legally treated as an in-kind contribution. Because contribution limits are unlimited, coordination is not prohibited, but it triggers mandatory reporting by the candidate.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('05b72a8e5c797468', 'NE', '["state","county","municipal"]', 'finance_ethics', 'When and how must a Nebraska campaign committee terminate?', '["Closing a Nebraska campaign committee","NADC committee termination requirements","Final campaign finance report Nebraska"]', 'A candidate committee may formally terminate when it has achieved a zero cash balance, legally disposed of all unexpended funds, and resolved all outstanding debts or loans. The committee must file a final Campaign Statement and a formal Statement of Dissolution with the NADC.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('b78752a639b1962f', 'NE', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Nebraska?', '["NE independent expenditure reporting NADC","Disclosure for NE independent expenditure groups","Reporting thresholds for outside spending Nebraska"]', 'Any person, PAC, or entity that makes an independent expenditure of more than $250 advocating for or against a candidate must file a Report of Independent Expenditure (Form B-6) with the Nebraska Accountability and Disclosure Commission (NADC).', 'https://nadc.nebraska.gov/sites/default/files/doc/B-6%202026.pdf', 'Nebraska NADC - Form B-6', '2026-05-17', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('ca194fcd0605db6e', 'NE', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Nebraska?', '["Nebraska in-kind contribution valuation rules","Reporting non-monetary donations Nebraska campaign","Fair market value for in-kind gifts NE"]', 'In-kind contributions (donated goods, services, or discounts not available to the general public) must be reported to the NADC at their fair market value as of the time the contribution is received. They must be logged as both a receipt and an expenditure on the Campaign Statement.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC - Treasurer''s Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('91ff8d6d64faeacb', 'NE', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Nebraska?', '["Nebraska candidate personal loan limits","Can I pay myself back for a campaign loan in NE?","Reporting candidate loans in NADC"]', 'No. Because Nebraska imposes NO contribution limits on individuals, a candidate may loan or contribute an UNLIMITED amount of their own personal funds to their campaign committee. Loans must be properly documented on NADC disclosures and may be repaid from campaign contributions.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('922995553b3c300c', 'NE', '["state","county","municipal"]', 'finance_ethics', 'What can Nebraska candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in NE?","NE surplus campaign funds rules","Donating remaining campaign funds Nebraska"]', 'Unexpended campaign funds cannot be converted to personal use. Under NADC rules, candidates may carry surplus funds forward to a future campaign, transfer them to a political party committee, transfer them to another candidate committee, return them to contributors, or donate them to an IRS-recognized tax-exempt charity.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC - Treasurer''s Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('0bf372d197bb0284', 'NE', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Nebraska legislators?', '["Can Nebraska legislators raise money during session?","Lobbyist contribution ban NE Unicameral","Legislative session contribution rules Nebraska"]', 'No. Nebraska does NOT have a ''session freeze.'' State Senators and statewide executive officials are legally permitted to solicit and accept campaign contributions while the Unicameral Legislature is actively in session.', 'https://nadc.nebraska.gov/', 'Nebraska NADC', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates and Lobbyists', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('ae6dc9676ed881c3', 'NE', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Nebraska?', '["NE PAC donation limits to candidates 2026","Political committee vs individual contribution limit Nebraska","Maximum PAC gift to state legislator NE"]', 'In Nebraska, Political Action Committees (PACs) are subject to the EXACT SAME rules as individuals and corporations: there are NO contribution limits. A PAC may contribute an UNLIMITED amount of money to any candidate for statewide or legislative office.', 'https://nadc.nebraska.gov/candidate-committee-treasurers-guide', 'Nebraska NADC', '2026-05-17', 'static', 'official_source_direct', 'State and County candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('a9544952852192c7', 'NE', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Nebraska?', '["When are county sheriffs elected in NE?","Nebraska county official term lengths","Are county commissioners on the 2026 ballot?"]', 'Elected county officials in Nebraska—including County Commissioners, Clerks, Treasurers, and Sheriffs—serve four-year staggered terms. Elections for these offices occur during standard primary and general elections, meaning numerous county seats will be on the 2026 ballot.', 'https://sos.nebraska.gov/elections/information-candidates', 'Nebraska Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('2635a16889fb80d1', 'NE', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Nebraska elections?', '["When are Nebraska election results official?","NE certification deadline","State Canvassing Board meeting Nebraska"]', 'County canvassing boards meet shortly after Election Day to certify local returns and submit them to the Secretary of State. The Nebraska Board of State Canvassers officially convenes on the fourth Monday after the election to certify the final statewide and federal election returns.', 'https://nebraskalegislature.gov/laws/statutes.php?statute=32-1037', 'Nebraska Revised Statutes § 32-1037', '2026-05-17', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('36fa586bf7d4e3fe', 'NE', '["federal","state"]', 'election_dates', 'When and how are special elections called in Nebraska?', '["Nebraska special election timeline","Who calls a special election to fill a US House vacancy in NE?","Filling a midterm vacancy Nebraska"]', 'Special elections to fill a vacancy in the U.S. House of Representatives or the State Legislature are called by a writ of election issued by the Governor. The Governor sets the dates for the special election, which is then administered by the Secretary of State and local county clerks.', 'https://sos.nebraska.gov/', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('115a3d1f5f82315e', 'NE', '["judicial"]', 'election_dates', 'What is the election cycle for Nebraska Supreme Court justices?', '["When do NE Supreme Court justices run?","Nebraska judicial retention elections","Terms for Nebraska Supreme Court"]', 'Under Nebraska''s merit selection system, a newly appointed Supreme Court justice must face a retention election (''Yes'' or ''No'' vote) at the first general election that occurs more than three years after their appointment. If retained by the voters, they serve a full six-year term before facing another retention election.', 'https://supremecourt.nebraska.gov/administration/judicial-nominating-commission', 'Nebraska Judicial Branch', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1'),
  ('d7eafe8cf6fecef3', 'NE', '["federal","state","county"]', 'runoff_rules', 'Does Nebraska hold general election runoffs if no candidate reaches a certain threshold?', '["Are there runoffs in Nebraska general elections?","Nebraska majority vote requirement general election","What happens if no one gets 50% in NE?"]', 'No. Nebraska does not hold runoff elections for the general election. The candidate who receives a simple plurality (the highest number of votes) is declared the winner, even if they do not secure a 50%+1 majority. (Note: The nonpartisan legislature uses a top-two primary, guaranteeing only two candidates advance to the general).', 'https://sos.nebraska.gov/elections/voter-information', 'Nebraska Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-18T00-30-09_nebraska_full_v1')
